     "name": "generate_document",
     "arguments": {
       "document_type": "aviso_de_ineligibilidade",
       "template": "modelo_interno",
       "data": {
         "employee_id": "[ID_DO_DENUNCIANTE]",
         "reason": "Não atende ao requisito de 1 ano ininterrupto de colaboração com compliance",
         "effective_date": "2025-01-02"
       },
       "official": true
     }
   }
   ```

